parameters.jsCode:
const raw = ($json.message || $json.message_text || "").toLowerCase();

// ---------------- NORMALIZATION ----------------
const msg = raw
  .replace(/[,₹]/g, " ")
  .replace(/crores?/g, "cr")
  .replace(/rs\.?/g, "")
  .replace(/\s+/g, " ")
  .trim();

// ---------------- INIT ----------------
let size_preference = null;
let preferred_locations = null;
let facing = null;
let budget_min = null;
let budget_max = null;
let budget_estimate = null;
let scoreDelta = 0;

// Qualification flags
let sizeQualified = false;
let facingQualified = false;
let locationQualified = false;
let budgetQualified = false;

// =======================================================
// ---------------- SIZE EXTRACTION ----------------
// =======================================================

let sizeText = msg.replace(/to/g, "-");

// RANGE (1800-2200, 18-19, 18to1900)
let sizeRangeMatch = sizeText.match(/(\d{2,4})\s*-\s*(\d{2,4})/);

if (sizeRangeMatch) {
  let min = parseInt(sizeRangeMatch[1]);
  let max = parseInt(sizeRangeMatch[2]);

  // shorthand fix (18 → 1800)
  if (min < 100) min *= 100;
  if (max < 100) max *= 100;

  // fix reversed
  if (min > max) [min, max] = [max, min];

  size_preference = `${min}-${max}`;

  if (min >= 2365 && max <= 3105) {
    sizeQualified = true;
    scoreDelta += 25;
  } else {
    scoreDelta -= 10;
  }
}

// SINGLE VALUE
else {
  let singleMatch = sizeText.match(/\b(\d{2,4})\b/);

  if (singleMatch) {
    let val = parseInt(singleMatch[1]);

    if (val < 100) val *= 100;

    size_preference = val;

    if (val >= 2365 && val <= 3105) {
      sizeQualified = true;
      scoreDelta += 25;
    } else {
      scoreDelta -= 10;
    }
  }
}

// =======================================================
// ---------------- FACING ----------------
// =======================================================

const facingPatterns = [
  "north east", "north west", "south east", "south west",
  "east", "west", "north", "south"
];

for (const f of facingPatterns) {
  if (msg.includes(f)) {
    facing = f.replace(/\s+/g, '-');

    if (f === "east" || f === "west") {
      facingQualified = true;
      scoreDelta += 15;
    } else {
      scoreDelta -= 5;
    }
    break;
  }
}

// =======================================================
// ---------------- BUDGET ----------------
// =======================================================

// RANGE (1-1.2cr, 1 to 1.2 cr)
let rangeMatch = msg.match(/(\d+(\.\d+)?)\s*(?:-|to)\s*(\d+(\.\d+)?)(?:\s*)cr/);

// SINGLE (2cr, 1.5 cr)
let singleMatch = msg.match(/(\d+(\.\d+)?)(?:\s*)cr/);

// LAKH (80 lakh)
let lakhMatch = msg.match(/(\d+(\.\d+)?)(?:\s*)lakh/);

if (rangeMatch) {
  budget_min = parseFloat(rangeMatch[1]);
  budget_max = parseFloat(rangeMatch[3]);
  budget_estimate = (budget_min + budget_max) / 2;

  if (budget_max >= 2.25) {
    budgetQualified = true;
    scoreDelta += 25;
  } else {
    scoreDelta -= 15;
  }

} else if (singleMatch) {
  budget_estimate = parseFloat(singleMatch[1]);

  if (budget_estimate >= 2.25) {
    budgetQualified = true;
    scoreDelta += 25;
  } else {
    scoreDelta -= 15;
  }

} else if (lakhMatch) {
  const val = parseFloat(lakhMatch[1]) / 100;
  budget_estimate = parseFloat(val.toFixed(2));

  if (budget_estimate >= 2.25) {
    budgetQualified = true;
    scoreDelta += 25;
  } else {
    scoreDelta -= 15;
  }
}

// =======================================================
// ---------------- LOCATION ----------------
// =======================================================

let locText = msg
  .replace(/[^a-z\s]/g, " ")
  .replace(/\s+/g, " ")
  .trim();

// canonical mapping + typo tolerance
const locationMap = {
  "manikonda": ["manikonda"],
  "puppalaguda": ["puppalaguda", "puppalguda", "pupplagudda", "puplaguda"],
  "gachibowli": ["gachibowli", "gachiboli"],
  "kondapur": ["kondapur"],
  "kokapet": ["kokapet"],
  "narsingi": ["narsingi"],
  "madhapur": ["madhapur"],
  "financial district": ["financial district", "fin dist"]
};

for (const [canonical, variants] of Object.entries(locationMap)) {
  for (const variant of variants) {
    if (locText.includes(variant)) {
      preferred_locations = canonical;
      break;
    }
  }
  if (preferred_locations) break;
}

// intent-based
if (!preferred_locations) {
  if (locText.includes("any") || locText.includes("open")) {
    preferred_locations = "flexible";
  }
}

// fallback (short message likely location)
if (!preferred_locations) {
  if (locText.split(" ").length <= 3) {
    preferred_locations = locText;
  }
}

// qualification
if (preferred_locations === "manikonda") {
  locationQualified = true;
  scoreDelta += 20;
} else if (preferred_locations) {
  scoreDelta -= 10;
}

// =======================================================
// ---------------- SCORE CLAMP ----------------
// =======================================================

scoreDelta = Math.max(0, Math.min(100, scoreDelta));

// =======================================================
// ---------------- OUTPUT ----------------
// =======================================================

return [
  {
    ...$json,
    message_text: raw,
    size_preference,
    preferred_locations,
    facing,
    budget_min,
    budget_max,
    budget_estimate,
    scoreDelta,
    qualification: {
      sizeQualified,
      facingQualified,
      locationQualified,
      budgetQualified
    }
  }
];

const messages = $input.all().map(item => item.json);

const formatted = messages
  .map(m => `${m.role}: ${m.message_text}`)
  .join('\n');

return [
  {
    formatted_history: formatted
  }
];
